SELECT department_name, location
FROM departments
WHERE department_head_id NOT IN (
  SELECT employee_id
  FROM employee_salary_grades
);

SELECT employee_id 
FROM promotions 
WHERE promotion_date = (SELECT MAX(promotion_date) FROM promotions);

SELECT accident_id, employee_id
FROM work_accidents
WHERE severity = 'major';

SELECT users.user_name 
FROM users
JOIN promotions ON users.user_id = promotions.employee_id;
